+            evidence_level: EvidenceLevel::Standard,
+            ..provider_terms()
+        };
+        let err = provider.validate_against(&c).unwrap_err();
+        assert!(matches!(
+            err,
+            ServiceContractError::ProviderEvidenceBelowContract { .. }
+        ));
+    }
